GitHub Release amalgamated 版本CMake FetchContent <p>1. 源代码文件 <code>test.cpp</code></p> <pre><code>#define CATCH_CONFIG_MAIN
#include "catch_amalgamated.hpp"
</code></pre> <p>2. 编译命令</p> <pre><code>g++ test.cpp catch_amalgamated.cpp -std=c++17 -o test
</code></pre> <pre><code>FetchContent_Declare(
Catch2
GIT_REPOSITORY https://github.com/catchorg/Catch2.git
GIT_TAG v3.5.2
)
</code></pre> <p>然后：</p> <pre><code>#include &lt;catch2/catch_test_macros.hpp&gt;
</code></pre>

C++C <pre><code>w.run();
</code></pre> <pre><code>webview_run(w);
</code></pre>

C++C <pre><code>#include "webview/webview.h"
#include &lt;iostream&gt;

int main() {
    try {
        webview::webview w(false, nullptr);
        w.set_title("示例");
        w.set_size(800, 600, WEBVIEW_HINT_NONE);
        w.set_html("&lt;h1&gt;Hello, WebView!&lt;/h1&gt;");
        w.run();
    } catch (const webview::exception &amp;e) {
        std::cerr &lt;&lt; e.what() &lt;&lt; std::endl;
        return 1;
    }
    return 0;
}
</code></pre> <pre><code>#include "webview/webview.h"

int main() {
    webview_t w = webview_create(0, NULL);
    webview_set_title(w, "示例");
    webview_set_size(w, 800, 600, WEBVIEW_HINT_NONE);
    webview_set_html(w, "&lt;h1&gt;Hello, WebView!&lt;/h1&gt;");
    webview_run(w);
    webview_destroy(w);
    return 0;
}
</code></pre>
